 1→import { Injectable, Logger } from '@nestjs/common';
 2→import { GitHub } from 'arctic';
 3→
 4→import {
 5→	GITHUB_CALLBACK_URL,
 6→	GITHUB_CLIENT_ID,
 7→	GITHUB_CLIENT_SECRET,
 8→} from '@constants/env-variables.constant';
 9→import { EnvConfigService } from '@modules/env-config/env-config.service';
10→import { IOAuthProfile } from '@modules/auth/types/auth.interface';
11→
12→@Injectable()
13→export class GithubStrategy {
14→	private readonly github: GitHub;
15→	private readonly logger = new Logger(GithubStrategy.name);
16→
17→	constructor(private readonly configService: EnvConfigService) {
18→		const clientId = this.configService.get<string>({ key: GITHUB_CLIENT_ID });
19→		const clientSecret = this.configService.get<string>({ key: GITHUB_CLIENT_SECRET });
20→		const callbackUrl = this.configService.get<string>({ key: GITHUB_CALLBACK_URL });
21→
22→		this.github = new GitHub(clientId, clientSecret, callbackUrl);
23→	}
24→
25→	createAuthorizationURL({ state }: { state: string; codeVerifier: string }): URL {
26→		return this.github.createAuthorizationURL(state, ['user:email']);
27→	}
28→
29→	async validateAuthorizationCode({
30→		code,
31→	}: {
32→		code: string;
33→		codeVerifier: string;
34→	}): Promise<{ accessToken: string }> {
35→		const tokens = await this.github.validateAuthorizationCode(code);
36→		return { accessToken: tokens.accessToken() };
37→	}
38→
39→	async getUserProfile({ accessToken }: { accessToken: string }): Promise<IOAuthProfile> {
40→		try {
41→			const response = await fetch('https://api.github.com/user', {
42→				headers: {
43→					Authorization: `Bearer ${accessToken}`,
44→					Accept: 'application/json',
45→				},
46→			});
47→
48→			if (!response.ok) {
49→				throw new Error(`GitHub API returned ${response.status}`);
50→			}
51→
52→			const data = (await response.json()) as {
53→				id: number;
54→				email: string | null;
55→				name: string | null;
56→				avatar_url: string | null;
57→				login: string;
58→			};
59→
60→			let email = data.email;
61→
62→			if (!email) {
63→				const emailsResponse = await fetch('https://api.github.com/user/emails', {
64→					headers: {
65→						Authorization: `Bearer ${accessToken}`,
66→						Accept: 'application/json',
67→					},
68→				});
69→
70→				if (!emailsResponse.ok) {
71→					throw new Error(`GitHub emails API returned ${emailsResponse.status}`);
72→				}
73→
74→				const emails = (await emailsResponse.json()) as Array<{
75→					email: string;
76→					primary: boolean;
77→					verified: boolean;
78→				}>;
79→
80→				const primaryEmail = emails.find((e) => e.primary && e.verified);
81→				email = primaryEmail?.email ?? null;
82→			}
83→
84→			return {
85→				provider: 'github',
86→				provider_id: String(data.id),
87→				email: email ?? '',
88→				name: data.name,
89→				avatar_url: data.avatar_url,
90→			};
91→		} catch (error) {
92→			this.logger.error('Failed to fetch GitHub user profile', error);
93→			throw error;
94→		}
95→	}
96→}
