import { IsNotEmpty, IsString } from 'class-validator';

export class TokenExchangeDto {
	@IsString()
	@IsNotEmpty()
	code: string;
}

import { IsNotEmpty, IsString } from 'class-validator';

export class LinkAccountDto {
	@IsString()
	@IsNotEmpty()
	linking_token: string;
}

import { IsNotEmpty, IsString, MaxLength } from 'class-validator';

export class CreateCompanyDto {
	@IsString()
	@IsNotEmpty()
	@MaxLength(255)
	name: string;
}

import { randomBytes, randomUUID } from 'crypto';

import { Inject, Injectable, Logger, UnauthorizedException } from '@nestjs/common';
import { JwtService } from '@nestjs/jwt';
import { generateCodeVerifier } from 'arctic';
import { Redis } from 'ioredis';

import { ENCRYPTION_KEY, JWT_ACCESS_TOKEN_EXPIRY } from '@constants/env-variables.constant';
import { REDIS_READ_CLIENT, REDIS_WRITE_CLIENT } from '@modules/cache/cache.constant';
import { EnvConfigService } from '@modules/env-config/env-config.service';
import {
	AUTH_CODE_TTL,
	LINKING_TOKEN_TTL,
	OAUTH_STATE_TTL,
} from '@modules/auth/constants/auth.constant';
import { GithubStrategy } from '@modules/auth/strategies/github.strategy';
import { GoogleStrategy } from '@modules/auth/strategies/google.strategy';
import {
	IAuthCode,
	IJwtPayload,
	ILinkingToken,
} from '@modules/auth/types/auth.interface';
import { CompanyMemberService } from '@modules/company-member/company-member.service';
import { CompanyService } from '@modules/company/company.service';
import { OAuthAccountService } from '@modules/oauth-account/oauth-account.service';
import { SessionService } from '@modules/session/session.service';
import { ISession } from '@modules/session/types/session.interface';
import { UserService } from '@modules/user/user.service';

interface IOAuthState {
	codeVerifier: string;
	provider: 'github' | 'google';
	invitationToken?: string;
}

@Injectable()
export class AuthService {
	private readonly logger = new Logger(AuthService.name);

	constructor(
		private readonly githubStrategy: GithubStrategy,
		private readonly googleStrategy: GoogleStrategy,
		private readonly userService: UserService,
		private readonly oauthAccountService: OAuthAccountService,
		private readonly companyMemberService: CompanyMemberService,
		private readonly companyService: CompanyService,
		private readonly sessionService: SessionService,
		private readonly jwtService: JwtService,
		private readonly configService: EnvConfigService,
		@Inject(REDIS_WRITE_CLIENT) private readonly redisWrite: Redis,
		@Inject(REDIS_READ_CLIENT) private readonly redisRead: Redis,
	) {}

	private getStrategy({
		provider,
	}: {
		provider: 'github' | 'google';
	}): GithubStrategy | GoogleStrategy {
		if (provider === 'github') {
			return this.githubStrategy;
		}
		return this.googleStrategy;
	}

	async initiateOAuth({
		provider,
		invitationToken,
	}: {
		provider: 'github' | 'google';
		invitationToken?: string;
	}): Promise<URL> {
		this.logger.log('Initiating OAuth', { provider });

		const state = randomBytes(32).toString('hex');
		const codeVerifier = generateCodeVerifier();

		const stateData: IOAuthState = { codeVerifier, provider };
		if (invitationToken !== undefined) {
			stateData.invitationToken = invitationToken;
		}

		await this.redisWrite.set(
			`oauth_state:${state}`,
			JSON.stringify(stateData),
			'EX',
			OAUTH_STATE_TTL,
		);

		const strategy = this.getStrategy({ provider });
		return strategy.createAuthorizationURL({ state, codeVerifier });
	}

	async handleCallback({
		provider,
		code,
		state,
	}: {
		provider: 'github' | 'google';
		code: string;
		state: string;
	}): Promise<
		| { type: 'auth_code'; code: string }
		| { type: 'linking_required'; linkingToken: string }
	> {
		this.logger.log('Handling OAuth callback', { provider });

		const stateKey = `oauth_state:${state}`;
		const raw = await this.redisWrite.getdel(stateKey);

		if (!raw) {
			throw new UnauthorizedException('Invalid or expired OAuth state');
		}

		const stateData = JSON.parse(raw) as IOAuthState;
		const strategy = this.getStrategy({ provider });

		const { accessToken } = await strategy.validateAuthorizationCode({
			code,
			codeVerifier: stateData.codeVerifier,
		});

		const profile = await strategy.getUserProfile({ accessToken });

		const existingOAuthAccount = await this.oauthAccountService.findByProviderAndProviderId({
			provider: profile.provider,
			providerId: profile.provider_id,
		});

		if (existingOAuthAccount) {
			await this.userService.updateLastLogin({ userId: existingOAuthAccount.user_id });

			const authCode = randomBytes(32).toString('hex');
			const authCodeData: IAuthCode = {
				user_id: existingOAuthAccount.user_id,
				session_id: randomUUID(),
			};

			await this.redisWrite.set(
				`auth_code:${authCode}`,
				JSON.stringify(authCodeData),
				'EX',
				AUTH_CODE_TTL,
			);

			return { type: 'auth_code', code: authCode };
		}

		const existingUser = profile.email
			? await this.userService.findByEmail({ email: profile.email })
			: null;

		if (existingUser) {
			const linkingToken = randomBytes(32).toString('hex');
			const linkingTokenData: ILinkingToken = {
				provider: profile.provider,
				provider_id: profile.provider_id,
				provider_email: profile.email,
				existing_user_id: existingUser._id,
				access_token: accessToken,
			};

			await this.redisWrite.set(
				`linking_token:${linkingToken}`,
				JSON.stringify(linkingTokenData),
				'EX',
				LINKING_TOKEN_TTL,
			);

			return { type: 'linking_required', linkingToken };
		}

		const newUser = await this.userService.create({
			data: {
				email: profile.email,
				name: profile.name,
				avatar_url: profile.avatar_url,
			},
		});

		await this.oauthAccountService.create({
			data: {
				user_id: newUser._id,
				provider: profile.provider,
				provider_id: profile.provider_id,
				email: profile.email || null,
				access_token: accessToken,
			},
		});

		const authCode = randomBytes(32).toString('hex');
		const authCodeData: IAuthCode = {
			user_id: newUser._id,
			session_id: randomUUID(),
		};

		await this.redisWrite.set(
			`auth_code:${authCode}`,
			JSON.stringify(authCodeData),
			'EX',
			AUTH_CODE_TTL,
		);

		return { type: 'auth_code', code: authCode };
	}

	async exchangeCode({
		code,
		ip,
		userAgent,
		provider,
	}: {
		code: string;
		ip: string;
		userAgent: string;
		provider: 'github' | 'google';
	}): Promise<{ accessToken: string; refreshToken: string }> {
		this.logger.log('Exchanging auth code for tokens');

		const raw = await this.redisWrite.getdel(`auth_code:${code}`);

		if (!raw) {
			throw new UnauthorizedException('Invalid or expired auth code');
		}

		const authCodeData = JSON.parse(raw) as IAuthCode;
		const { user_id, session_id } = authCodeData;

		const memberships = await this.companyMemberService.findByUserId({ userId: user_id });
		const firstMembership = memberships[0] ?? null;

		const refreshToken = randomUUID();
		const now = new Date().toISOString();

		const session: ISession = {
			user_id,
			session_id,
			role: firstMembership ? firstMembership.role : null,
			company_id: firstMembership ? firstMembership.company_id : null,
			provider,
			ip,
			user_agent: userAgent,
			created_at: now,
			last_active: now,
		};

		await this.sessionService.createSession({ session, refreshToken });

		const expiry = this.configService.get<string>({ key: JWT_ACCESS_TOKEN_EXPIRY });

		const payload: IJwtPayload = {
			user_id,
			session_id,
			role: session.role,
			company_id: session.company_id,
		};

		const accessToken = await this.jwtService.signAsync(payload, { expiresIn: expiry });

		return { accessToken, refreshToken };
	}

	async refreshTokens({
		refreshToken,
		ip,
		userAgent,
	}: {
		refreshToken: string;
		ip: string;
		userAgent: string;
	}): Promise<{ accessToken: string; refreshToken: string }> {
		this.logger.log('Refreshing tokens');

		const tokenData = await this.sessionService.validateRefreshToken({ refreshToken });

		if (!tokenData) {
			const reuseData = await this.sessionService.detectRefreshTokenReuse({ refreshToken });

			if (reuseData) {
				await this.sessionService.destroySession({
					userId: reuseData.user_id,
					sessionId: reuseData.session_id,
				});
			}

			throw new UnauthorizedException('Invalid or expired refresh token');
		}

		const { user_id, session_id } = tokenData;

		const session = await this.sessionService.getSession({ userId: user_id, sessionId: session_id });

		if (!session) {
			throw new UnauthorizedException('Session not found');
		}

		const newRefreshToken = await this.sessionService.rotateRefreshToken({
			oldToken: refreshToken,
			session,
		});

		await this.sessionService.updateLastActive({ userId: user_id, sessionId: session_id });

		const expiry = this.configService.get<string>({ key: JWT_ACCESS_TOKEN_EXPIRY });

		const payload: IJwtPayload = {
			user_id,
			session_id,
			role: session.role,
			company_id: session.company_id,
		};

		const accessToken = await this.jwtService.signAsync(payload, { expiresIn: expiry });

		return { accessToken, refreshToken: newRefreshToken };
	}

	async linkAccount({
		linkingToken,
		userId,
	}: {
		linkingToken: string;
		userId: string;
	}): Promise<void> {
		this.logger.log('Linking OAuth account', { userId });

		const raw = await this.redisWrite.getdel(`linking_token:${linkingToken}`);

		if (!raw) {
			throw new UnauthorizedException('Invalid or expired linking token');
		}

		const tokenData = JSON.parse(raw) as ILinkingToken;

		if (tokenData.existing_user_id !== userId) {
			throw new UnauthorizedException('Linking token does not match user');
		}

		await this.oauthAccountService.create({
			data: {
				user_id: userId,
				provider: tokenData.provider,
				provider_id: tokenData.provider_id,
				email: tokenData.provider_email || null,
				access_token: tokenData.access_token,
			},
		});
	}

	async createCompany({
		name,
		userId,
		sessionId,
	}: {
		name: string;
		userId: string;
		sessionId: string;
	}): Promise<{ company_id: string }> {
		this.logger.log('Creating company', { userId });

		const company = await this.companyService.create({ data: { name } });

		await this.companyMemberService.create({
			data: {
				user_id: userId,
				company_id: company._id,
				role: 'admin',
			},
		});

		await this.sessionService.updateCompanyContext({
			userId,
			sessionId,
			companyId: company._id,
			role: 'admin',
		});

		return { company_id: company._id };
	}

	async logout({
		userId,
		sessionId,
	}: {
		userId: string;
		sessionId: string;
	}): Promise<void> {
		this.logger.log('Logging out', { userId, sessionId });
		await this.sessionService.destroySession({ userId, sessionId });
	}

	async logoutAll({ userId }: { userId: string }): Promise<void> {
		this.logger.log('Logging out all sessions', { userId });
		await this.sessionService.destroyAllSessions({ userId });
	}
}

