				600,
			);
			expect(mockGithubStrategy.createAuthorizationURL).toHaveBeenCalledWith({
				state: 'mock-random-hex',
				codeVerifier: 'mock-code-verifier',
			});
			expect(result).toBeInstanceOf(URL);
		});

		it('should store invitation token in OAuth state when provided', async () => {
			await service.initiateOAuth({
				provider: 'google',
				invitationToken: 'invite-token-abc',
			});

			expect(mockRedisWrite.set).toHaveBeenCalledWith(
				'oauth_state:mock-random-hex',
				JSON.stringify({
					codeVerifier: 'mock-code-verifier',
					provider: 'google',
					invitationToken: 'invite-token-abc',
				}),
				'EX',
				600,
			);
			expect(mockGoogleStrategy.createAuthorizationURL).toHaveBeenCalled();
		});
	});

	describe('handleCallback', () => {
		const stateData = JSON.stringify({
			codeVerifier: 'stored-verifier',
			provider: 'github',
		});

		it('should return auth_code when existing oauth_account is found', async () => {
			mockRedisWrite.getdel.mockResolvedValue(stateData);
			mockOAuthAccountService.findByProviderAndProviderId.mockResolvedValue({
				_id: 'oauth-1',
				user_id: 'user-123',
				provider: 'github',
				provider_id: 'gh-123',
			});

			const result = await service.handleCallback({
				provider: 'github',
				code: 'oauth-code',
				state: 'valid-state',
			});

			expect(mockUserService.updateLastLogin).toHaveBeenCalledWith({ userId: 'user-123' });
			expect(mockRedisWrite.set).toHaveBeenCalledWith(
				'auth_code:mock-random-hex',
				expect.any(String),
				'EX',
				60,
			);
			expect(result).toEqual({ type: 'auth_code', code: 'mock-random-hex' });
		});

		it('should return linking_required when email matches existing user but no oauth_account', async () => {
			mockRedisWrite.getdel.mockResolvedValue(stateData);
			mockOAuthAccountService.findByProviderAndProviderId.mockResolvedValue(null);
			mockUserService.findByEmail.mockResolvedValue({
				_id: 'existing-user-456',
				email: 'user@example.com',
			});

			const result = await service.handleCallback({
				provider: 'github',
				code: 'oauth-code',
				state: 'valid-state',
			});

			expect(mockRedisWrite.set).toHaveBeenCalledWith(
				'linking_token:mock-random-hex',
				expect.stringContaining('existing-user-456'),
				'EX',
				300,
			);
			expect(result).toEqual({ type: 'linking_required', linkingToken: 'mock-random-hex' });
		});

		it('should create user + oauth_account and return auth_code when no match', async () => {
			mockRedisWrite.getdel.mockResolvedValue(stateData);
			mockOAuthAccountService.findByProviderAndProviderId.mockResolvedValue(null);
			mockUserService.findByEmail.mockResolvedValue(null);
			mockUserService.create.mockResolvedValue({
				_id: 'new-user-789',
				email: 'user@example.com',
			});

			const result = await service.handleCallback({
				provider: 'github',
				code: 'oauth-code',
				state: 'valid-state',
			});

			expect(mockUserService.create).toHaveBeenCalled();
			expect(mockOAuthAccountService.create).toHaveBeenCalledWith({
				data: expect.objectContaining({ user_id: 'new-user-789', provider: 'github' }),
			});
			expect(result).toEqual({ type: 'auth_code', code: 'mock-random-hex' });
		});

		it('should throw UnauthorizedException when state is invalid or expired', async () => {
			mockRedisWrite.getdel.mockResolvedValue(null);

			await expect(
				service.handleCallback({
					provider: 'github',
					code: 'oauth-code',
					state: 'bad-state',
				}),
			).rejects.toThrow(UnauthorizedException);
		});
	});

	describe('exchangeCode', () => {
		it('should validate code, create session, sign JWT, and return tokens', async () => {
			const authCodeData = JSON.stringify({
				user_id: 'user-123',
				session_id: 'mock-uuid',
			});
			mockRedisWrite.getdel.mockResolvedValue(authCodeData);
			mockCompanyMemberService.findByUserId.mockResolvedValue([
				{ user_id: 'user-123', company_id: 'company-abc', role: 'admin' },
			]);

			const result = await service.exchangeCode({
				code: 'valid-auth-code',
				ip: '127.0.0.1',
				userAgent: 'Mozilla/5.0',
				provider: 'github',
			});

			expect(mockSessionService.createSession).toHaveBeenCalledWith(
				expect.objectContaining({
					session: expect.objectContaining({
						user_id: 'user-123',
						company_id: 'company-abc',
						role: 'admin',
					}),
				}),
			);
			expect(mockJwtService.signAsync).toHaveBeenCalledWith(
				expect.objectContaining({ user_id: 'user-123' }),
				expect.any(Object),
			);
			expect(result).toEqual({
				accessToken: 'mock-jwt-token',
				refreshToken: 'mock-uuid',
			});
		});

		it('should use role: null and company_id: null when user has no company memberships', async () => {
			const authCodeData = JSON.stringify({
				user_id: 'user-no-company',
				session_id: 'mock-uuid',
			});
			mockRedisWrite.getdel.mockResolvedValue(authCodeData);
			mockCompanyMemberService.findByUserId.mockResolvedValue([]);

			await service.exchangeCode({
				code: 'valid-auth-code',
				ip: '127.0.0.1',
				userAgent: 'Mozilla/5.0',
				provider: 'github',
			});

			expect(mockSessionService.createSession).toHaveBeenCalledWith(
				expect.objectContaining({
					session: expect.objectContaining({
						role: null,
						company_id: null,
					}),
				}),
			);
			expect(mockJwtService.signAsync).toHaveBeenCalledWith(
				expect.objectContaining({ role: null, company_id: null }),
				expect.any(Object),
			);
		});

		it('should throw UnauthorizedException when code is invalid', async () => {
			mockRedisWrite.getdel.mockResolvedValue(null);

			await expect(
				service.exchangeCode({
					code: 'bad-code',
					ip: '127.0.0.1',
					userAgent: 'Mozilla/5.0',
					provider: 'github',
				}),
			).rejects.toThrow(UnauthorizedException);
		});
	});

	describe('refreshTokens', () => {
		it('should validate token, rotate, update last_active, sign new JWT, and return tokens', async () => {
			mockSessionService.validateRefreshToken.mockResolvedValue({
				user_id: 'user-123',
				session_id: 'session-456',
			});
			mockSessionService.getSession.mockResolvedValue(mockSession);
			mockSessionService.rotateRefreshToken.mockResolvedValue('new-refresh-token');

			const result = await service.refreshTokens({
				refreshToken: 'valid-refresh-token',
				ip: '127.0.0.1',
				userAgent: 'Mozilla/5.0',
			});

			expect(mockSessionService.rotateRefreshToken).toHaveBeenCalledWith(
				expect.objectContaining({ oldToken: 'valid-refresh-token' }),
			);
			expect(mockSessionService.updateLastActive).toHaveBeenCalledWith({
				userId: 'user-123',
				sessionId: 'session-456',
			});
			expect(result).toEqual({
				accessToken: 'mock-jwt-token',
				refreshToken: 'new-refresh-token',
			});
		});

		it('should destroy session and throw UnauthorizedException on token reuse', async () => {
			mockSessionService.validateRefreshToken.mockResolvedValue(null);
			mockSessionService.detectRefreshTokenReuse.mockResolvedValue({
				user_id: 'user-123',
				session_id: 'session-456',
			});

			await expect(
				service.refreshTokens({
					refreshToken: 'reused-refresh-token',
					ip: '127.0.0.1',
					userAgent: 'Mozilla/5.0',
				}),
			).rejects.toThrow(UnauthorizedException);

			expect(mockSessionService.destroySession).toHaveBeenCalledWith({
				userId: 'user-123',
				sessionId: 'session-456',
			});
		});

		it('should throw UnauthorizedException when token is invalid and no reuse detected', async () => {
			mockSessionService.validateRefreshToken.mockResolvedValue(null);
			mockSessionService.detectRefreshTokenReuse.mockResolvedValue(null);

			await expect(
				service.refreshTokens({
					refreshToken: 'invalid-refresh-token',
					ip: '127.0.0.1',
					userAgent: 'Mozilla/5.0',
				}),
			).rejects.toThrow(UnauthorizedException);

			expect(mockSessionService.destroySession).not.toHaveBeenCalled();
		});
	});

	describe('linkAccount', () => {
		it('should validate linking token and create oauth_account', async () => {
			const linkingTokenData = JSON.stringify({
				provider: 'github',
				provider_id: 'gh-123',
				provider_email: 'user@example.com',
				existing_user_id: 'user-123',
				access_token: 'gh-access-token',
			});
			mockRedisWrite.getdel.mockResolvedValue(linkingTokenData);

			await service.linkAccount({
				linkingToken: 'valid-linking-token',
				userId: 'user-123',
			});

			expect(mockOAuthAccountService.create).toHaveBeenCalledWith({
				data: expect.objectContaining({
					user_id: 'user-123',
					provider: 'github',
					provider_id: 'gh-123',
				}),
			});
		});

		it('should throw UnauthorizedException when linking token is invalid', async () => {
			mockRedisWrite.getdel.mockResolvedValue(null);

			await expect(
				service.linkAccount({
					linkingToken: 'bad-linking-token',
					userId: 'user-123',
				}),
			).rejects.toThrow(UnauthorizedException);
		});

		it('should throw UnauthorizedException when userId does not match token', async () => {
			const linkingTokenData = JSON.stringify({
				provider: 'github',
				provider_id: 'gh-123',
				provider_email: 'user@example.com',
				existing_user_id: 'different-user',
				access_token: 'gh-access-token',
			});
			mockRedisWrite.getdel.mockResolvedValue(linkingTokenData);

			await expect(
				service.linkAccount({
					linkingToken: 'valid-linking-token',
					userId: 'user-123',
				}),
			).rejects.toThrow(UnauthorizedException);
		});
	});

	describe('createCompany', () => {
		it('should create company, add admin member, update session, and return company_id', async () => {
			mockCompanyService.create.mockResolvedValue({
				_id: 'company-new',
				name: 'Acme Corp',
			});
			mockCompanyMemberService.create.mockResolvedValue({
				_id: 'member-1',
				user_id: 'user-123',
				company_id: 'company-new',
				role: 'admin',
			});

			const result = await service.createCompany({
				name: 'Acme Corp',
				userId: 'user-123',
				sessionId: 'session-456',
			});

			expect(mockCompanyService.create).toHaveBeenCalledWith({
				data: { name: 'Acme Corp' },
			});
			expect(mockCompanyMemberService.create).toHaveBeenCalledWith({
				data: {
					user_id: 'user-123',
					company_id: 'company-new',
					role: 'admin',
				},
			});
			expect(mockSessionService.updateCompanyContext).toHaveBeenCalledWith({
				userId: 'user-123',
				sessionId: 'session-456',
				companyId: 'company-new',
				role: 'admin',
			});
			expect(result).toEqual({ company_id: 'company-new' });
		});
	});

	describe('logout', () => {
		it('should delegate to sessionService.destroySession', async () => {
			await service.logout({ userId: 'user-123', sessionId: 'session-456' });

			expect(mockSessionService.destroySession).toHaveBeenCalledWith({
				userId: 'user-123',
				sessionId: 'session-456',
			});
		});
	});

	describe('logoutAll', () => {
		it('should delegate to sessionService.destroyAllSessions', async () => {
			await service.logoutAll({ userId: 'user-123' });

			expect(mockSessionService.destroyAllSessions).toHaveBeenCalledWith({
				userId: 'user-123',
			});
		});
	});
});

